```class Solution {
    public int maxScore(int[] nums) {
        Arrays.sort(nums);
        int res = 0, i = 0, j = nums.length - 1;
        while (i < j) {
            res += nums[i] * nums[j] / gcd(nums[i], nums[j]);
            i++;
            j--;
        }
        return res;
    }
    private int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}```
